	artwork_id, member_id, category_id, is_status,
	title, content, view_count, reg_dt, mod_dt, comp_dt
) VALUES (
	#{artworkId}, #{memberId}, #{categoryId}, #{isStatus},
	#{title}, #{content}, 0, SYSDATE, NULL,

		SYSDATE

		#{compDt,jdbcType=DATE}

