UPDATE artwork SET title = #{title}, content = #{content},
category_id = #{categoryId},
mod_dt = SYSDATE WHERE artwork_id = #{artworkId}

UPDATE artwork
   SET view_count = view_count + 1
 WHERE artwork_id = #{artworkId}

