SELECT * FROM ( SELECT a.artwork_id, a.member_id, a.category_id, a.is_status, a.title, a.content, a.view_count, a.reg_dt, a.mod_dt, a.comp_dt, m.nickname, c.category_nm, (SELECT COUNT(*) FROM board_like l WHERE l.target_type = 'ARTWORK' AND l.target_id = a.artwork_id) AS like_count FROM artwork a JOIN member m ON a.member_id = m.member_id JOIN category c ON a.category_id = c.category_id
AND a.is_status = #{isStatus}
ORDER BY a.reg_dt DESC, a.artwork_id DESC ) WHERE ROWNUM <= #{pageSize}

SELECT FROM artwork a JOIN member m ON a.member_id = m.member_id JOIN category c ON a.category_id = c.category_id WHERE a.member_id = #{memberId}
AND a.is_status = #{isStatus}
ORDER BY a.artwork_id DESC
